sql:
SELECT name, location_id
FROM user_profiles
WHERE years_of_experience > 5;

SELECT level_name, average_salary
FROM job_levels
ORDER BY average_salary DESC;

external_knowledge:
- "shimmering stars" refers to the top-paying jobs; 
- "sparkle the most" is used metaphorically to describe the highest average salary; 
- "budding startups" indicates emerging companies, which are excluded by the condition "company_type != 'startup'";
- "celestrial lights of established sectors" metaphorically describes the industries of non-startup companies.

sql:
SELECT AVG(s.base_salary) AS average_salary
FROM job_applications ja
INNER JOIN salary_data s ON ja.job_id = s.job_id;

SELECT AVG(average_salary) AS average_salary_by_level
FROM job_levels
WHERE average_salary > 100000;
